/*
 * 		% : 나머지값 출력
 * 			결과값은 언제나 왼쪽부호를 따라감.
 * 			5 % 2 = 1
 * 		   -5 % 2 = -1
 * 		   -5 % -2 = -1
 * 			5 % -2 = 1
 */
public class 이항연산자_산술연산자 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		System.out.println(5%2);
		System.out.println(-5%2);
		System.out.println(5%-2);
		System.out.println(-5%-2);
		
	}

}
